 64	    pub fn syntaxError(self: *Lexer) !void {
 65	        @branchHint(.cold);
 66	
 67	        // Only add this if there is not already an error.
 68	        // It is possible that there is a more descriptive error already emitted.
 69	        if (!self.log.hasErrors())
 70	            self.addError(self.start, "Syntax Error", .{});
 71	
 72	        return Error.SyntaxError;
 73	    }
