 75	    pub fn addError(self: *Lexer, _loc: usize, comptime format: []const u8, args: anytype) void {
 76	        @branchHint(.cold);
 77	
 78	        var __loc = logger.usize2Loc(_loc);
 79	        if (__loc.eql(self.prev_error_loc)) {
 80	            return;
 81	        }
 82	
 83	        self.log.addErrorFmtOpts(
 84	            self.log.msgs.allocator,
 85	            format,
 86	            args,
 87	            .{
 88	                .source = &self.source,
 89	                .loc = __loc,
 90	                .redact_sensitive_information = self.should_redact_logs,
 91	            },
 92	        ) catch unreachable;
 93	        self.prev_error_loc = __loc;
 94	    }
