126	    /// Look ahead at the next n codepoints without advancing the iterator.
127	    /// If fewer than n codepoints are available, then return the remainder of the string.
128	    fn peek(it: *Lexer, n: usize) string {
129	        const original_i = it.current;
130	        defer it.current = original_i;
131	
132	        var end_ix = original_i;
133	        var found: usize = 0;
134	        while (found < n) : (found += 1) {
135	            const next_codepoint = it.nextCodepointSlice();
136	            if (next_codepoint.len == 0) break;
137	            end_ix += next_codepoint.len;
138	        }
139	
140	        return it.source.contents[original_i..end_ix];
141	    }
142	
143	    inline fn nextCodepointSlice(it: *Lexer) []const u8 {
144	        if (it.current >= it.source.contents.len) {
145	            return "";
146	        }
147	        const cp_len = strings.wtf8ByteSequenceLengthWithInvalid(it.source.contents.ptr[it.current]);
148	        return if (!(cp_len + it.current > it.source.contents.len)) it.source.contents[it.current .. cp_len + it.current] else "";
149	    }
150	
151	    inline fn nextCodepoint(it: *Lexer) CodePoint {
152	        if (it.current >= it.source.contents.len) {
153	            it.end = it.source.contents.len;
154	            return -1;
155	        }
156	        const cp_len = strings.wtf8ByteSequenceLengthWithInvalid(it.source.contents.ptr[it.current]);
157	        const slice = if (!(cp_len + it.current > it.source.contents.len)) it.source.contents[it.current .. cp_len + it.current] else "";
158	
159	        const code_point = switch (slice.len) {
160	            0 => -1,
161	            1 => @as(CodePoint, slice[0]),
162	            else => strings.decodeWTF8RuneTMultibyte(slice.ptr[0..4], @as(u3, @intCast(slice.len)), CodePoint, strings.unicode_replacement),
163	        };
164	
165	        it.end = it.current;
166	
167	        it.current += if (code_point != strings.unicode_replacement)
168	            cp_len
169	        else
170	            1;
171	
172	        return code_point;
173	    }
174	
175	    inline fn step(lexer: *Lexer) void {
176	        lexer.code_point = lexer.nextCodepoint();
177	
178	        lexer.line_number += @as(u32, @intFromBool(lexer.code_point == '\n'));
179	    }
