190	    fn parseNumericLiteralOrDot(lexer: *Lexer) !void {
191	        // Number or dot;
192	        const first = lexer.code_point;
193	        lexer.step();
194	
195	        // Dot without a digit after it;
196	        if (first == '.' and (lexer.code_point < '0' or lexer.code_point > '9')) {
197	
198	            // "."
199	            lexer.token = T.t_dot;
200	            return;
201	        }
202	
203	        var underscoreCount: usize = 0;
204	        var lastUnderscoreEnd: usize = 0;
205	        var hasDotOrExponent = first == '.';
206	        var base: f32 = 0.0;
207	
208	        var is_legacy_octal_literal = false;
209	
210	        // Assume this is a number, but potentially change to a date/time later;
211	        lexer.token = T.t_numeric_literal;
212	
213	        // Check for binary, octal, or hexadecimal literal;
214	        if (first == '0') {
215	            switch (lexer.code_point) {
216	                'b', 'B' => {
217	                    base = 2;
218	                },
219	
220	                'o', 'O' => {
221	                    base = 8;
222	                },
223	
224	                'x', 'X' => {
225	                    base = 16;
226	                },
227	
228	                '0'...'7', '_' => {
229	                    base = 8;
230	                    is_legacy_octal_literal = true;
231	                },
232	                else => {},
233	            }
234	        }
235	
236	        if (base != 0) {
237	            // Integer literal;
238	            var isFirst = true;
239	            var isInvalidLegacyOctalLiteral = false;
240	            lexer.number = 0;
241	            if (!is_legacy_octal_literal) {
242	                lexer.step();
243	            }
244	
245	            integerLiteral: while (true) {
246	                switch (lexer.code_point) {
247	                    '_' => {
248	                        // Cannot have multiple underscores in a row;
249	                        if (lastUnderscoreEnd > 0 and lexer.end == lastUnderscoreEnd + 1) {
250	                            try lexer.syntaxError();
251	                        }
252	
253	                        // The first digit must exist;
254	                        if (isFirst or is_legacy_octal_literal) {
255	                            try lexer.syntaxError();
256	                        }
257	
258	                        lastUnderscoreEnd = lexer.end;
259	                        underscoreCount += 1;
260	                    },
261	
262	                    '0', '1' => {
263	                        lexer.number = lexer.number * base + float64(lexer.code_point - '0');
264	                    },
265	
266	                    '2', '3', '4', '5', '6', '7' => {
267	                        if (base == 2) {
268	                            try lexer.syntaxError();
269	                        }
270	                        lexer.number = lexer.number * base + float64(lexer.code_point - '0');
271	                    },
272	                    '8', '9' => {
273	                        if (is_legacy_octal_literal) {
274	                            isInvalidLegacyOctalLiteral = true;
275	                        } else if (base < 10) {
276	                            try lexer.syntaxError();
277	                        }
278	                        lexer.number = lexer.number * base + float64(lexer.code_point - '0');
279	                    },
280	                    'A', 'B', 'C', 'D', 'E', 'F' => {
281	                        if (base != 16) {
282	                            try lexer.syntaxError();
283	                        }
284	                        lexer.number = lexer.number * base + float64(lexer.code_point + 10 - 'A');
285	                    },
286	
287	                    'a', 'b', 'c', 'd', 'e', 'f' => {
288	                        if (base != 16) {
289	                            try lexer.syntaxError();
290	                        }
291	                        lexer.number = lexer.number * base + float64(lexer.code_point + 10 - 'a');
292	                    },
293	                    else => {
294	                        // The first digit must exist;
295	                        if (isFirst) {
296	                            try lexer.syntaxError();
297	                        }
298	
299	                        break :integerLiteral;
300	                    },
301	                }
302	
303	                lexer.step();
304	                isFirst = false;
305	            }
306	
307	            const isBigIntegerLiteral = lexer.code_point == 'n' and !hasDotOrExponent;
308	
309	            // Slow path: do we need to re-scan the input as text?
310	            if (isBigIntegerLiteral or isInvalidLegacyOctalLiteral) {
311	                const text = lexer.raw();
312	
313	                // Can't use a leading zero for bigint literals;
314	                if (isBigIntegerLiteral and is_legacy_octal_literal) {
315	                    try lexer.syntaxError();
316	                }
317	
318	                // Filter out underscores;
319	                if (underscoreCount > 0) {
320	                    var bytes = lexer.allocator.alloc(u8, text.len - underscoreCount) catch unreachable;
321	                    var i: usize = 0;
322	                    for (text) |char| {
323	                        if (char != '_') {
324	                            bytes[i] = char;
325	                            i += 1;
326	                        }
327	                    }
328	                }
329	
330	                // Store bigints as text to avoid precision loss;
331	                if (isBigIntegerLiteral) {
332	                    lexer.identifier = text;
333	                } else if (isInvalidLegacyOctalLiteral) {
334	                    if (std.fmt.parseFloat(f64, text)) |num| {
335	                        lexer.number = num;
336	                    } else |_| {
337	                        try lexer.addSyntaxError(lexer.start, "Invalid number {s}", .{text});
338	                    }
339	                }
340	            }
341	        } else {
342	            // Floating-point literal;
343	            const isInvalidLegacyOctalLiteral = first == '0' and (lexer.code_point == '8' or lexer.code_point == '9');
344	
345	            // Initial digits;
346	            while (true) {
347	                if (lexer.code_point < '0' or lexer.code_point > '9') {
348	                    switch (lexer.code_point) {
349	                        // '-' => {
350	                        //     if (lexer.raw().len == 5) {
351	                        //         // Is this possibly a datetime literal that begins with a 4 digit year?
352	                        //         lexer.step();
353	                        //         while (!lexer.has_newline_before) {
354	                        //             switch (lexer.code_point) {
355	                        //                 ',' => {
