357	                        //                     lexer.token = T.t_string_literal;
358	                        //                     break;
359	                        //                 },
360	                        //             }
361	                        //         }
362	                        //     }
363	                        // },
364	                        '_' => {},
365	                        else => break,
366	                    }
367	                    if (lexer.code_point != '_') {
368	                        break;
369	                    }
370	
371	                    // Cannot have multiple underscores in a row;
372	                    if (lastUnderscoreEnd > 0 and lexer.end == lastUnderscoreEnd + 1) {
373	                        try lexer.syntaxError();
374	                    }
375	
376	                    // The specification forbids underscores in this case;
377	                    if (isInvalidLegacyOctalLiteral) {
378	                        try lexer.syntaxError();
379	                    }
380	
381	                    lastUnderscoreEnd = lexer.end;
382	                    underscoreCount += 1;
383	                }
384	                lexer.step();
385	            }
386	
387	            // Fractional digits;
388	            if (first != '.' and lexer.code_point == '.') {
389	                // An underscore must not come last;
390	                if (lastUnderscoreEnd > 0 and lexer.end == lastUnderscoreEnd + 1) {
391	                    lexer.end -= 1;
392	                    try lexer.syntaxError();
393	                }
394	
395	                hasDotOrExponent = true;
396	                lexer.step();
397	                if (lexer.code_point == '_') {
398	                    try lexer.syntaxError();
399	                }
400	                while (true) {
401	                    if (lexer.code_point < '0' or lexer.code_point > '9') {
402	                        if (lexer.code_point != '_') {
403	                            break;
404	                        }
405	
406	                        // Cannot have multiple underscores in a row;
407	                        if (lastUnderscoreEnd > 0 and lexer.end == lastUnderscoreEnd + 1) {
408	                            try lexer.syntaxError();
409	                        }
410	
411	                        lastUnderscoreEnd = lexer.end;
412	                        underscoreCount += 1;
413	                    }
414	                    lexer.step();
415	                }
416	            }
417	
418	            // Exponent;
419	            if (lexer.code_point == 'e' or lexer.code_point == 'E') {
420	                // An underscore must not come last;
421	                if (lastUnderscoreEnd > 0 and lexer.end == lastUnderscoreEnd + 1) {
422	                    lexer.end -= 1;
423	                    try lexer.syntaxError();
424	                }
425	
426	                hasDotOrExponent = true;
427	                lexer.step();
428	                if (lexer.code_point == '+' or lexer.code_point == '-') {
429	                    lexer.step();
430	                }

